     1→import { TransactionType, PointsDetailProps } from "./Models";
     2→
     3→type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     4→type TagSubType = 'DRIVE_THRU' | 'PEDAGIO' | 'ESTACIONAMENTO' | 'ABASTECIMENTO' | 'LAVA_RAPIDO';
     5→
     6→
     7→export const getTransactionGainType = (transaction: PointsDetailProps['transaction']): TransactionGainType => {
     8→  const provider = transaction.details?.provider?.toLowerCase() || '';
     9→  
    10→  if (provider.includes('cashback')) {
    11→    return 'CASHBACK';
    12→  }
    13→  
    14→  const icon = transaction.icon?.toLowerCase() || '';
    15→  const description = transaction.description?.toLowerCase() || '';
    16→  
    17→  const tagIndicators = ['tag', 'pedágio', 'pedagio', 'estacionamento', 'abastecimento', 'abastece', 'drive', 'lava', 'rápido'];
    18→  
    19→  const isTag = tagIndicators.some(indicator => 
    20→    icon.includes(indicator) || 
    21→    description.includes(indicator) || 
    22→    provider.includes(indicator)
    23→  );
    24→  
    25→  return isTag ? 'TAG' : 'CARD';
    26→};
    27→
    28→export const getTagSubType = (transaction: PointsDetailProps['transaction']): TagSubType | null => {
    29→  const description = transaction.description?.toUpperCase() || '';
    30→  const provider = transaction.details?.provider?.toUpperCase() || '';
    31→  const extraInfo = transaction.details?.extraInfo?.toUpperCase() || '';
    32→  const searchText = `${description} ${provider} ${extraInfo}`;
    33→  
    34→  if (searchText.includes('DRIVE') || searchText.includes('DRIVE-THRU') || searchText.includes('DRIVE THRU')) {
    35→    return 'DRIVE_THRU';
    36→  }
    37→  if (searchText.includes('PEDÁGIO') || searchText.includes('PEDAGIO')) {
